function extractJSON(text) {
  if (!text) return null;
  const raw = String(text).trim();
  try { return JSON.parse(raw); } catch {}
  const start = raw.indexOf('{');
  const end = raw.lastIndexOf('}');
  if (start >= 0 && end > start) {
    try { return JSON.parse(raw.slice(start, end + 1)); } catch {}
  }
  return null;
}

export async function requestStructuredMode({ feature, prompt, usage, fallback, setStatus }) {
  const gate = await usage.consume(feature);
  if (!gate.allowed) return { locked: true, gate };

  try {
    setStatus?.(`${feature.toUpperCase()} - OPENING UT ORACLE ROUTE`);
    const response = await usage.askOracle(prompt, { mode: 'symbolic', language: 'en' });
    const rawAnswer = response?.answer || response?.text || response;
    const answer = typeof rawAnswer === 'string' ? rawAnswer : JSON.stringify(rawAnswer || '');
    const parsed = extractJSON(answer);
    if (parsed) return { ...parsed, source: 'ut', gate };
    const local = fallback();
    return { ...local, deep_reading: answer || local.deep_reading, source: 'ut-text', gate };
  } catch {
    setStatus?.(`${feature.toUpperCase()} - LOCAL CHAMBER FALLBACK`);
    return { ...fallback(), source: 'local', gate };
  }
}
