function getGlyph(name, category) {
  if (GLYPHS[name]) return GLYPHS[name];
  // Category-based fallbacks
  const fallbacks = {
    PLANETS:'◎',ZODIAC:'◈',ELEMENTS:'△',METALS:'◇',COLORS:'●',
    NUMBERS:'◉',MAJOR_ARCANA:'◫',KABBALAH:'◬',PLATONIC_SOLIDS:'◻',
    GEOMETRY:'◯',ARCHETYPES:'◑',CRYSTALS:'◆',PHYSIOLOGY:'◒',
    MAYAN:'▣',GEOMANCY:'⁙',I_CHING:'☰',LETTERS_HEBREW:'◮',LETTERS_LATIN:'◧',
    DEITIES:'★',PLANTS:'❀',FREQUENCY:'∿',VICES:'⚠',NOTES:'♪',ALCHEMY:'⊕',VIRTUES:'✦',CHAKRAS:'✺'
  };
  if (category === 'CHAKRAS') return CHAKRA_STYLES[chakraStyleFor(name)]?.glyph || '✺';
  // For Hebrew letters
  if (category === 'LETTERS_HEBREW') return name.charAt(0);
  // For colors
  if (category === 'COLORS') return '◉';
  // For geometry
  if (name.toLowerCase().includes('circle')) return '○';
  if (name.toLowerCase().includes('triangle')) return '△';
  if (name.toLowerCase().includes('square')) return '□';
  if (name.toLowerCase().includes('pentagram')) return '⛤';
  if (name.toLowerCase().includes('hexagram')) return '✡';
  if (name.toLowerCase().includes('spiral')) return '🌀';
  return fallbacks[category] || '◈';
}

function getColorForEntry(entry, category) {
  const meta = CAT_META[category];
  if (!meta) return '#00f5ff';
  const first = String(entry || '').split(';')[0].trim();
  // Special color overrides
  if (category === 'COLORS') {
    const colorMap = {
      'Red':'#ff2244','Orange':'#ff8800','Yellow':'#ffdd00','Green':'#00cc44',
      'Blue':'#0066ff','Violet':'#9933ff','Purple':'#7722cc','White':'#e8f0ff',
      'Black':'#334466','Gold':'#c9a84c','Silver':'#99aacc','Crimson':'#cc1133',
      'Indigo':'#4444cc','Emerald':'#00bb66','Amber':'#ff9900','Rose':'#ff6688',
    };
    return colorMap[first] || meta.color;
  }
  if (category === 'ELEMENTS') {
    const em = {'Fire':'#ff4400','Water':'#0088ff','Earth':'#886633','Air':'#aaccff','Aether':'#cc88ff'};
    return em[first] || meta.color;
  }
  if (category === 'CHAKRAS') return CHAKRA_STYLES[chakraStyleFor(first)]?.color || meta.color;
  return meta.color;
}

