// BACKGROUND ANIMATION - hyperspace correspondence field
(function initBG() {
  const cv = document.getElementById('bgCanvas');
  const cx = cv.getContext('2d');
  let W = 0, H = 0, stars = [], columns = [], comets = [], nodes = [], shards = [];
  const rand = (min, max) => min + Math.random() * (max - min);

  function resetStar(star, initial = false) {
    star.x = rand(-1, 1);
    star.y = rand(-1, 1);
    star.z = initial ? rand(0.12, 1) : 1;
    star.pz = star.z;
    star.hue = Math.random() > 0.72 ? 45 : (Math.random() > 0.5 ? 185 : 275);
  }

  function resize() {
    W = cv.width = window.innerWidth;
    H = cv.height = window.innerHeight;
    const starCount = Math.max(RENDER_PROFILE.minStars, Math.floor((W * H) / 5200 * RENDER_PROFILE.bgDensity));
    stars = Array.from({length: starCount}, () => { const s = {}; resetStar(s, true); return s; });
    const columnCount = Math.max(8, Math.floor(Math.max(18, Math.floor(W / 46)) * RENDER_PROFILE.columns));
    columns = Array.from({length: columnCount}, (_, i) => ({
      x: (i / Math.max(1, columnCount)) * W + rand(-8, 8),
      phase: rand(0, Math.PI * 2),
      tone: Math.random() > 0.5 ? '34,211,238' : '201,168,76',
      motes: Array.from({length: Math.floor(rand(4, 10))}, () => ({y: rand(0, H), sp: rand(0.28, 1.15), r: rand(0.55, 1.7), a: rand(0.025, 0.07)}))
    }));
    comets = Array.from({length: 4}, (_, i) => ({
      x: rand(0, W), y: rand(0, H), vx: rand(2.4, 5.8) * (i % 2 ? -1 : 1), vy: rand(-0.55, 1.3),
      tail: [], hue: i % 2 ? 42 : 188, next: rand(0, 3)
    }));
    nodes = Array.from({length: Math.max(8, Math.floor(18 * RENDER_PROFILE.nodes))}, () => ({x: rand(60, W - 60), y: rand(60, H - 60), vx: rand(-0.24, 0.24), vy: rand(-0.22, 0.22), r: rand(1.2, 2.5), p: rand(0, Math.PI * 2)}));
    shards = Array.from({length: Math.max(4, Math.floor(9 * RENDER_PROFILE.shards))}, () => ({x: rand(0, W), y: rand(0, H), s: rand(10, 28), r: rand(0, Math.PI * 2), rs: rand(-0.012, 0.012), dx: rand(-0.18, 0.18), dy: rand(-0.12, 0.12), hue: rand(165, 250)}));
  }

  function drawWarp(t) {
    const cx0 = W * 0.5, cy0 = H * 0.52;
    const focal = Math.min(W, H) * (0.56 + Math.sin(t * 0.36) * 0.03);
    const speed = 0.0048 + Math.max(0, Math.sin(t * 0.28)) * 0.004;
    for (const s of stars) {
      const px = cx0 + (s.x / s.pz) * focal;
      const py = cy0 + (s.y / s.pz) * focal;
      s.z -= speed;
      if (s.z <= 0.035) resetStar(s);
      const x = cx0 + (s.x / s.z) * focal;
      const y = cy0 + (s.y / s.z) * focal;
      s.pz = s.z;
      if (x < -60 || x > W + 60 || y < -60 || y > H + 60) { resetStar(s); continue; }
      const a = Math.min(0.62, (1 - s.z) * 0.7);
      cx.lineWidth = Math.max(0.45, (1 - s.z) * 2.1);
      cx.strokeStyle = `hsla(${s.hue},95%,68%,${a})`;
      cx.beginPath(); cx.moveTo(px, py); cx.lineTo(x, y); cx.stroke();
    }
    const g = cx.createRadialGradient(cx0, cy0, 10, cx0, cy0, Math.min(W, H) * 0.55);
    g.addColorStop(0, 'rgba(0,245,255,0.035)');
    g.addColorStop(0.42, 'rgba(157,78,221,0.018)');
    g.addColorStop(1, 'rgba(0,0,0,0)');
    cx.fillStyle = g;
    cx.fillRect(0, 0, W, H);
  }

  function draw() {
    requestAnimationFrame(draw);
    const t = performance.now() * 0.001;
    cx.fillStyle = 'rgba(0,3,5,0.2)';
    cx.fillRect(0, 0, W, H);
    drawWarp(t);

    for (const col of columns) {
      const pulse = 0.018 + Math.sin(t * 1.2 + col.phase) * 0.011;
      cx.strokeStyle = `rgba(${col.tone},${Math.max(0.006, pulse)})`;
      cx.lineWidth = 0.35;
      cx.beginPath(); cx.moveTo(col.x, 0); cx.lineTo(col.x + Math.sin(t + col.phase) * 12, H); cx.stroke();
      for (const m of col.motes) {
        m.y += m.sp;
        if (m.y > H + 10) m.y = -10;
        cx.beginPath(); cx.arc(col.x + Math.sin(m.y * 0.012 + col.phase) * 5, m.y, m.r, 0, Math.PI * 2);
        cx.fillStyle = `rgba(${col.tone},${m.a})`; cx.fill();
      }
    }

    for (const shard of shards) {
      shard.x += shard.dx; shard.y += shard.dy; shard.r += shard.rs;
      if (shard.x < -60) shard.x = W + 60; if (shard.x > W + 60) shard.x = -60;
      if (shard.y < -60) shard.y = H + 60; if (shard.y > H + 60) shard.y = -60;
      cx.save(); cx.translate(shard.x, shard.y); cx.rotate(shard.r);
      const drawShard = (ox, rgb, a) => {
        cx.beginPath(); cx.moveTo(ox, -shard.s); cx.lineTo(ox + shard.s * 0.72, 0); cx.lineTo(ox, shard.s); cx.lineTo(ox - shard.s * 0.48, 0); cx.closePath();
        cx.strokeStyle = `rgba(${rgb},${a})`; cx.fillStyle = `rgba(${rgb},${a * 0.08})`; cx.lineWidth = 0.9; cx.stroke(); cx.fill();
      };
      drawShard(-2, '255,60,86', 0.28); drawShard(2, '0,245,255', 0.34); drawShard(0, '201,168,76', 0.26);
      cx.restore();
    }

    for (const comet of comets) {
      comet.x += comet.vx; comet.y += comet.vy + Math.sin(t + comet.hue) * 0.08;
      if (comet.x > W + 90 || comet.x < -90 || comet.y > H + 90 || comet.y < -90) {
        comet.x = comet.vx > 0 ? -60 : W + 60;
        comet.y = rand(H * 0.15, H * 0.85);
        comet.tail = [];
      }
      comet.tail.push({x: comet.x, y: comet.y});
      if (comet.tail.length > 26) comet.tail.shift();
      cx.lineCap = 'round';
      for (let i = 1; i < comet.tail.length; i++) {
        const a = i / comet.tail.length;
        const p = comet.tail[i - 1], q = comet.tail[i];
        cx.lineWidth = a * 4;
        cx.strokeStyle = `hsla(${comet.hue},90%,65%,${a * 0.26})`;
        cx.beginPath(); cx.moveTo(p.x - comet.vx * 0.3, p.y - 2); cx.lineTo(q.x, q.y); cx.stroke();
        cx.strokeStyle = `rgba(255,55,85,${a * 0.16})`;
        cx.beginPath(); cx.moveTo(p.x + 5, p.y + 1); cx.lineTo(q.x + 5, q.y + 1); cx.stroke();
      }
      const glow = cx.createRadialGradient(comet.x, comet.y, 0, comet.x, comet.y, 24);
      glow.addColorStop(0, 'rgba(255,255,255,0.72)'); glow.addColorStop(0.35, `hsla(${comet.hue},95%,60%,0.28)`); glow.addColorStop(1, 'rgba(0,0,0,0)');
      cx.fillStyle = glow; cx.fillRect(comet.x - 24, comet.y - 24, 48, 48);
    }

    for (let i = 0; i < nodes.length; i++) {
      const n = nodes[i];
      n.x += n.vx; n.y += n.vy; n.p += 0.026;
      if (n.x < 45 || n.x > W - 45) n.vx *= -1;
      if (n.y < 45 || n.y > H - 45) n.vy *= -1;
      for (let j = i + 1; j < nodes.length; j++) {
        const o = nodes[j], dx = o.x - n.x, dy = o.y - n.y, d = Math.hypot(dx, dy);
        if (d < 165) {
          const a = (1 - d / 165) * 0.12;
          cx.strokeStyle = `rgba(0,245,255,${a})`; cx.lineWidth = 0.7;
          cx.beginPath(); cx.moveTo(n.x, n.y); cx.quadraticCurveTo((n.x + o.x) / 2, (n.y + o.y) / 2 + Math.sin(t + i) * 8, o.x, o.y); cx.stroke();
        }
      }
      const rr = n.r * (1 + Math.sin(n.p) * 0.25);
      cx.fillStyle = 'rgba(0,245,255,0.42)'; cx.beginPath(); cx.arc(n.x + 1.2, n.y, rr, 0, Math.PI * 2); cx.fill();
      cx.fillStyle = 'rgba(255,60,86,0.26)'; cx.beginPath(); cx.arc(n.x - 1.2, n.y, rr, 0, Math.PI * 2); cx.fill();
    }
  }

  resize(); draw(); window.addEventListener('resize', resize);
})();

// STATE
let state = {activeCategory:null, activeEntry:null, compareA:null, compareB:null, compareMode:false, searchQuery:''};
let ritualModes = null;

const SYSTEM_ORDER = Object.keys(CODEX);
const DISPLAY_FIELD_ORDER = [...SYSTEM_ORDER];
const ALL_ENTRY_REFS = SYSTEM_ORDER.flatMap(cat => (CODEX[cat] || []).map((entry, idx) => ({cat, idx, entry})));
const EXACT_ENTRY_LOOKUP = {};
SYSTEM_ORDER.forEach(cat => {
  EXACT_ENTRY_LOOKUP[cat] = {};
  (CODEX[cat] || []).forEach((entry, idx) => {
    entryAliases(getEntryName(cat, entry)).forEach(alias => registerEntryAlias(cat, alias, idx));
  });
});
let entryBag = [];

function shuffleInPlace(arr) {
  for (let i = arr.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1));
    [arr[i], arr[j]] = [arr[j], arr[i]];
  }
  return arr;
}

function nextEntryRef() {
  if (!entryBag.length) entryBag = shuffleInPlace(ALL_ENTRY_REFS.slice());
  return entryBag.pop();
}

function getEntryName(cat, entry) {
  return entry?.[cat] || Object.values(entry || {})[0] || '';
}

function registerEntryAlias(cat, alias, idx) {
  if (!alias || !EXACT_ENTRY_LOOKUP[cat]) return;
  const existing = EXACT_ENTRY_LOOKUP[cat][alias];
  if (existing === undefined) EXACT_ENTRY_LOOKUP[cat][alias] = idx;
}

function entryAliases(value) {
  const aliases = new Set();
  const add = raw => {
    const name = normalizeName(raw);
    if (!name) return;
    aliases.add(name);
    [
      name.replace(/^[^\p{L}\p{N}]+/u, ''),
      name.replace(/^[^a-z0-9]+/i, ''),
      name.replace(/^\d+\s*[-:.)]?\s*/, ''),
      name.replace(/\s+(other|greek|norse|hindu|angelic|egyptian|mayan|sumerian)$/i, ''),
      name.replace(/\s*\[[^\]]+\]\s*$/, ''),
      name.replace(/^\d+\s*[-:.)]?\s*/,'').replace(/^[^\p{L}\p{N}]+/u, ''),
      name.replace(/^[^\p{L}\p{N}]+/u, '').replace(/^\d+\s*[-:.)]?\s*/, '')
    ].forEach(alias => {
      alias = normalizeName(alias);
      if (alias) aliases.add(alias);
    });
  };
  splitValues(value).forEach(add);
  add(value);
  return Array.from(aliases);
}

function fieldOrder(entry, includeVirtues = true) {
  const order = includeVirtues ? DISPLAY_FIELD_ORDER : SYSTEM_ORDER;
  return order.filter(key => entry && entry[key] && CAT_META[key]);
}

function resolveEntryRef(cat, rawName) {
  if (!CODEX[cat]) return null;
  const candidates = entryAliases(rawName);
  for (const candidate of candidates) {
    const idx = EXACT_ENTRY_LOOKUP[cat]?.[candidate];
    if (Number.isInteger(idx) && idx >= 0) return {cat, idx, entry:CODEX[cat][idx], mode:'exact'};
  }
  return null;
}

function targetAttrs(cat, value) {
  const ref = resolveEntryRef(cat, value);
  if (ref) return ` data-target-cat="${escapeHTML(ref.cat)}" data-target-idx="${ref.idx}" data-target-mode="${ref.mode}"`;
  return ` data-open-cat="${escapeHTML(cat)}" data-target-missing="${escapeHTML(value)}"`;
}

function renderLinkedValues(cat, value, tokenClass = 'value-link') {
  const parts = splitValues(value);
  if (!parts.length) return escapeHTML(value);
  return parts.map(part => `<span class="${tokenClass}"${targetAttrs(cat, part)}>${escapeHTML(part)}</span>`).join('<span class="value-sep">; </span>');
}

