function selectCategory(cat) {
  if (!CODEX[cat]) return;
  pointerDown = false;
  clearHoverState();
  destroyCardCube();
  closeOracle();
  state.activeCategory = cat;
  document.querySelectorAll('.cat-item').forEach(el => el.classList.toggle('active', el.dataset.cat === cat));
  showCategoryView(cat);
  setStatus(`${(CAT_META[cat]?.label||cat)} - ${CODEX[cat]?.length||0} ENTRIES`);
}

function showCategoryView(cat) {
  destroyCardCube();
  const meta = CAT_META[cat];
  const entries = CODEX[cat] || [];
  const overlay = document.getElementById('cardOverlay');
  let html = `<div style="width:100%;max-width:700px">
    <div class="catview-header">
      <div>
        <div class="catview-icon" style="color:${meta.color}">${meta.icon} ${escapeHTML((meta.label||cat).toUpperCase())} CATEGORY</div>
        <div class="catview-title" style="color:${meta.color}">${escapeHTML((meta.label||cat.replace(/_/g,' ')).toUpperCase())}</div>
        <div class="catview-count">${entries.length} Entries</div>
      </div>
      <button class="card-close-btn" onclick="closeOverlay()">X</button>
    </div>
    <div class="entry-list">`;
  entries.forEach((entry, i) => {
    const name = getEntryName(cat, entry);
    const glyph = getGlyph(name, cat);
    const color = getColorForEntry(name, cat);
    const hints = [];
    if (entry.PLANETS && cat!=='PLANETS') hints.push(entry.PLANETS.split(';')[0].trim());
    if (entry.ELEMENTS && cat!=='ELEMENTS') hints.push(entry.ELEMENTS.split(';')[0].trim());
    if (entry.ALCHEMY && cat!=='ALCHEMY') hints.push(entry.ALCHEMY.split(';')[0].trim());
    html += `<div class="entry-card" data-entry-cat="${escapeHTML(cat)}" data-entry-idx="${i}">
      <div class="entry-glyph" style="color:${color}">${glyph}</div>
      <div class="entry-info">
        <div class="entry-name">${escapeHTML(name)}</div>
        <div class="entry-sub">${escapeHTML(hints.slice(0,3).join(' - '))}</div>
      </div>
      <div class="entry-arrow">-&gt;</div>
    </div>`;
  });
  html += '</div></div>';
  overlay.innerHTML = html;
  overlay.classList.add('open');
}

function selectEntry(cat, idx) {
  if (!CODEX[cat]) return;
  const entry = CODEX[cat][Number(idx)];
  if (!entry) return;
  pointerDown = false;
  clearHoverState();
  state.activeEntry = {cat, idx:Number(idx), entry};
  
  if (state.compareMode) {
    handleCompareSelect(cat, entry);
    return;
  }
  
  showEntryCard(cat, entry);
  showOraclePanel(cat, entry);
}

