let synthesisVoice = {utterance:null, text:''};
const AUTO_PLAY_SYNTHESIS = true;

// Easy edit zone for synthesis text. Add entries as:
// 'SYSTEM::ENTRY NAME': `flowing synthesis text`
const ENTRY_SYNTHESIS = {
  'CHAKRAS::HEART-ANAHATA': HEART_CHAKRA_SYNTHESIS
};

function synthesisKey(cat, entry) {
  return `${cat}::${getEntryName(cat, entry)}`;
}

function getSynthesisText(cat, entry) {
  return ENTRY_SYNTHESIS[synthesisKey(cat, entry)] || '';
}

function getSynthesisHTML(cat, entry) {
  const key = synthesisKey(cat, entry);
  const text = getSynthesisText(cat, entry);
  const display = text ? escapeHTML(text).replace(/\n/g,'<br><br>') : `Invoke a generated synthesis for ${escapeHTML(key)}. The free layer opens a compact reading; Initiate access deepens narration, variants, and saved chambers.`;
  return `<div class="synthesis-actions">
      <button class="audio-btn mode-primary-inline" onclick="openSynthesisMode()">INVOKE SYNTHESIS</button>
      <button class="audio-btn" id="synthesisPlayBtn" data-voice="en-US-Chirp3-HD-Zephyr" onclick="toggleSynthesisPlayback()" ${text ? '' : 'disabled'}>${text ? 'PLAY STATIC TEXT' : 'STATIC TEXT PENDING'}</button>
    </div>
    <div class="card-side-copy synthesis-copy" id="synthesisText" data-synthesis-key="${escapeHTML(key)}" data-text="${escapeHTML(text)}">${display}</div>`;
}

function toggleSynthesisPlayback() {
  const text = document.getElementById('synthesisText')?.dataset?.text || '';
  if (!text || !('speechSynthesis' in window)) return;
  const btn = document.getElementById('synthesisPlayBtn');
  if (speechSynthesis.speaking && !speechSynthesis.paused) {
    speechSynthesis.pause();
    if (btn) btn.textContent = 'RESUME';
    return;
  }
  if (speechSynthesis.paused) {
    speechSynthesis.resume();
    if (btn) btn.textContent = 'PAUSE';
    return;
  }
  speechSynthesis.cancel();
  const utterance = new SpeechSynthesisUtterance(text);
  utterance.lang = 'en-US';
  utterance.rate = 0.88;
  utterance.pitch = 1.03;
  const voices = speechSynthesis.getVoices?.() || [];
  utterance.voice = voices.find(v => /en-US/i.test(v.lang) && /Google|Female|Jenny|Aria|Samantha|Zira/i.test(v.name)) || voices.find(v => /en-US/i.test(v.lang)) || null;
  utterance.onend = () => { if (btn) btn.textContent = 'PLAY / PAUSE'; };
  synthesisVoice = {utterance, text};
  if (btn) btn.textContent = 'PAUSE';
  speechSynthesis.speak(utterance);
}

