function showEntryCard(cat, entry) {
  destroyCardCube();
  const meta = CAT_META[cat] || {color:'#00f5ff', label:cat, icon:''};
  const name = getEntryName(cat, entry);
  const glyph = getGlyph(name, cat);
  const color = getColorForEntry(name, cat);
  const overlay = document.getElementById('cardOverlay');
  const keys = fieldOrder(entry, true);
  const corrHTML = keys.map(key => {
    const km = CAT_META[key] || {color:'#00f5ff', label:key, icon:''};
    const isLink = key !== cat && CODEX[key];
    const valueHTML = isLink ? renderLinkedValues(key, entry[key], 'value-link') : escapeHTML(entry[key]);
    return `<div class="cc-row ${isLink ? 'has-links' : ''}">
      <div class="cc-field"><span style="color:${km.color}">${km.icon}</span> ${escapeHTML(km.label || key.replace(/_/g,' '))}</div>
      <div class="cc-val ${isLink ? 'link' : ''}">${valueHTML}</div>
    </div>`;
  }).join('');

  overlay.innerHTML = `<div class="card-wrap">
    <div class="card-left">
      <div class="card-top">
        <div class="card-glyph" style="color:${color}">${glyph}</div>
        <div class="card-entry-name">${escapeHTML(name)}</div>
        <div class="card-entry-cat"><span style="color:${meta.color}">${meta.icon}</span> ${escapeHTML((meta.label || cat).toUpperCase())}</div>
        <button class="card-close-btn" onclick="closeOverlay()">X</button>
      </div>
      <div class="card-corrs">${corrHTML}</div>
    </div>
    <div class="card-right">
      <div class="card-cube-container">
        <canvas id="cardCubeCanvas"></canvas>
        <div class="card-cube-tip" id="cardCubeTip"></div>
      </div>
      <div class="card-cube-label">TRANSLINGUISTIC TELEMETRY NODE</div>
      <div class="card-side-section">
        <div class="card-side-title">SYNTHESIS</div>
        ${getSynthesisHTML(cat, entry)}
      </div>
      <div class="card-side-section">
        <div class="card-side-title">SYMBOLISM</div>
        <div class="card-side-copy">Reserved for symbolic notes.</div>
      </div>
    </div>
  </div>`;
  overlay.classList.add('open');
  if (DEVICE_TIER === 'fallback' || !THREE) renderCardCubeFallback(cat, entry, glyph, color);
  else initCardCube(cat, entry);
  if (AUTO_PLAY_SYNTHESIS && getSynthesisText(cat, entry)) setTimeout(toggleSynthesisPlayback, 240);
}

