function getSymbolTexture(faceIndex, tint = '#00f5ff', label = '') {
  const key = symbolKeys.length ? symbolKeys[faceIndex % symbolKeys.length] : 'fallback';
  const cacheKey = `${key}|${tint}|${String(label).slice(0,8)}`;
  if (symbolTextures[cacheKey]) return symbolTextures[cacheKey];

  const size = DEVICE_TIER === 'lite' ? 256 : 512;
  const canvas = document.createElement('canvas');
  canvas.width = size;
  canvas.height = size;
  const ctx = canvas.getContext('2d');
  const rgb = hexToRgb(tint || '#00f5ff');
  const mark = String(label || key || '*').trim().slice(0, 3).toUpperCase();
  const hasSymbol = symbolKeys.length && SYMBOL_IMAGES[key];

  function paintBase(drawFallback = false) {
    ctx.clearRect(0, 0, size, size);
    ctx.save();
    const rr = 64;
    ctx.beginPath();
    ctx.moveTo(24 + rr, 24);
    ctx.lineTo(size - 24 - rr, 24);
    ctx.quadraticCurveTo(size - 24, 24, size - 24, 24 + rr);
    ctx.lineTo(size - 24, size - 24 - rr);
    ctx.quadraticCurveTo(size - 24, size - 24, size - 24 - rr, size - 24);
    ctx.lineTo(24 + rr, size - 24);
    ctx.quadraticCurveTo(24, size - 24, 24, size - 24 - rr);
    ctx.lineTo(24, 24 + rr);
    ctx.quadraticCurveTo(24, 24, 24 + rr, 24);
    ctx.closePath();
    ctx.clip();
    const g = ctx.createRadialGradient(size * .38, size * .28, 20, size * .5, size * .5, size * .72);
    g.addColorStop(0, 'rgba(18,31,34,.98)');
    g.addColorStop(.42, 'rgba(4,9,12,.98)');
    g.addColorStop(1, 'rgba(0,1,3,1)');
    ctx.fillStyle = g;
    ctx.fillRect(0, 0, size, size);
    const bevel = ctx.createLinearGradient(0, 0, size, size);
    bevel.addColorStop(0, 'rgba(255,255,255,.18)');
    bevel.addColorStop(.18, 'rgba(0,245,255,.08)');
    bevel.addColorStop(.5, 'rgba(0,0,0,0)');
    bevel.addColorStop(.78, 'rgba(0,0,0,.34)');
    bevel.addColorStop(1, 'rgba(0,0,0,.66)');
    ctx.fillStyle = bevel;
    ctx.fillRect(0, 0, size, size);
    const sheen = ctx.createLinearGradient(0, 0, size, size * .55);
    sheen.addColorStop(0, 'rgba(0,245,255,.18)');
    sheen.addColorStop(.22, 'rgba(255,255,255,.055)');
    sheen.addColorStop(.48, 'rgba(0,0,0,0)');
    sheen.addColorStop(1, 'rgba(0,0,0,0)');
    ctx.fillStyle = sheen;
    ctx.fillRect(0, 0, size, size);
    ctx.strokeStyle = 'rgba(255,255,255,.16)';
    ctx.lineWidth = 10;
    ctx.strokeRect(20, 20, size - 40, size - 40);
    ctx.strokeStyle = 'rgba(0,0,0,.58)';
    ctx.lineWidth = 12;
    ctx.beginPath(); ctx.moveTo(28, size - 24); ctx.lineTo(size - 24, size - 24); ctx.lineTo(size - 24, 28); ctx.stroke();
    ctx.strokeStyle = 'rgba(0,245,255,.12)';
    ctx.lineWidth = 5;
    ctx.beginPath(); ctx.moveTo(32, 32); ctx.lineTo(size - 34, 32); ctx.moveTo(32, 32); ctx.lineTo(32, size - 34); ctx.stroke();
    if (drawFallback) {
      ctx.fillStyle = 'rgba(246,252,255,.94)';
      ctx.font = '900 138px Orbitron, Arial, sans-serif';
      ctx.textAlign = 'center';
      ctx.textBaseline = 'middle';
      ctx.shadowColor = `rgba(${rgb},.55)`;
      ctx.shadowBlur = 16;
      ctx.fillText(mark, size / 2, size / 2 + 6);
      ctx.shadowBlur = 0;
    }
    ctx.restore();
  }

  paintBase(!hasSymbol);
  const tex = new THREE.CanvasTexture(canvas);
  tex.encoding = THREE.sRGBEncoding;
  tex.minFilter = DEVICE_TIER === 'lite' ? THREE.LinearFilter : THREE.LinearMipMapLinearFilter;
  tex.magFilter = THREE.LinearFilter;
  if (renderer) tex.anisotropy = Math.min(8, renderer.capabilities.getMaxAnisotropy());
  symbolTextures[cacheKey] = tex;

  if (hasSymbol) {
    const img = new Image();
    img.onload = () => {
      paintBase(false);
      const mask = document.createElement('canvas');
      mask.width = size;
      mask.height = size;
      const mctx = mask.getContext('2d');
      mctx.clearRect(0, 0, size, size);
      mctx.drawImage(img, 74, 74, size - 148, size - 148);
      mctx.globalCompositeOperation = 'source-in';
      mctx.fillStyle = 'rgba(228,236,246,.92)';
      mctx.fillRect(0, 0, size, size);
      ctx.drawImage(mask, 0, 0);
      ctx.save();
      ctx.globalCompositeOperation = 'source-atop';
      const glyphSheen = ctx.createLinearGradient(0, 0, 0, size * .72);
      glyphSheen.addColorStop(0, 'rgba(90,223,255,.32)');
      glyphSheen.addColorStop(.18, 'rgba(160,220,255,.12)');
      glyphSheen.addColorStop(.42, 'rgba(255,255,255,.03)');
      glyphSheen.addColorStop(1, 'rgba(0,0,0,0)');
      ctx.fillStyle = glyphSheen;
      ctx.fillRect(0, 0, size, size);
      ctx.restore();
      const topSheen = ctx.createLinearGradient(0, 0, 0, size * .28);
      topSheen.addColorStop(0, 'rgba(0,245,255,.14)');
      topSheen.addColorStop(1, 'rgba(0,245,255,0)');
      ctx.fillStyle = topSheen;
      ctx.fillRect(0, 0, size, size * .32);
      tex.needsUpdate = true;
    };
    img.src = SYMBOL_IMAGES[key];
  }
  return tex;
}

function getGlyphMaskTexture(faceIndex, label = '') {
  const key = symbolKeys.length ? symbolKeys[faceIndex % symbolKeys.length] : 'fallback';
  const cacheKey = `${key}|${String(label).slice(0,8)}|mask`;
  if (glyphMaskTextures[cacheKey]) return glyphMaskTextures[cacheKey];
  const size = DEVICE_TIER === 'lite' ? 256 : 512;
  const canvas = document.createElement('canvas');
  canvas.width = size;
  canvas.height = size;
  const ctx = canvas.getContext('2d');
  const mark = String(label || key || '*').trim().slice(0, 3).toUpperCase();
  const paintFallback = () => {
    ctx.clearRect(0, 0, size, size);
    ctx.fillStyle = 'rgba(255,255,255,.92)';
    ctx.font = '900 138px Orbitron, Arial, sans-serif';
    ctx.textAlign = 'center';
    ctx.textBaseline = 'middle';
    ctx.fillText(mark, size / 2, size / 2 + 6);
    tex.needsUpdate = true;
  };
  const tex = new THREE.CanvasTexture(canvas);
  tex.encoding = THREE.sRGBEncoding;
  tex.minFilter = DEVICE_TIER === 'lite' ? THREE.LinearFilter : THREE.LinearMipMapLinearFilter;
  tex.magFilter = THREE.LinearFilter;
  if (renderer) tex.anisotropy = Math.min(8, renderer.capabilities.getMaxAnisotropy());
  glyphMaskTextures[cacheKey] = tex;
  if (symbolKeys.length && SYMBOL_IMAGES[key]) {
    const img = new Image();
    img.onload = () => {
      ctx.clearRect(0, 0, size, size);
      const mask = document.createElement('canvas');
      mask.width = size;
      mask.height = size;
      const mctx = mask.getContext('2d');
      mctx.clearRect(0, 0, size, size);
      mctx.drawImage(img, 74, 74, size - 148, size - 148);
      mctx.globalCompositeOperation = 'source-in';
      mctx.fillStyle = 'rgba(232,240,250,.96)';
      mctx.fillRect(0, 0, size, size);
      ctx.drawImage(mask, 0, 0);
      ctx.save();
      ctx.globalCompositeOperation = 'source-atop';
      const maskSheen = ctx.createLinearGradient(0, 0, 0, size * .68);
      maskSheen.addColorStop(0, 'rgba(92,229,255,.85)');
      maskSheen.addColorStop(.25, 'rgba(255,255,255,.42)');
      maskSheen.addColorStop(1, 'rgba(255,255,255,.04)');
      ctx.fillStyle = maskSheen;
      ctx.fillRect(0, 0, size, size);
      ctx.restore();
      tex.needsUpdate = true;
    };
    img.onerror = paintFallback;
    img.src = SYMBOL_IMAGES[key];
  } else {
    paintFallback();
  }
  return tex;
}

function getRandomEntry() {
  const ref = nextEntryRef();
  return ref ? {...ref} : null;
}

function assignFaceEntries() {
  faceEntryMap = [];
  for (let i = 0; i < 54; i++) faceEntryMap.push(getRandomEntry());
}

function applyFaceData(mesh, data, highlight = false) {
  if (!mesh || !mesh.material || !data) return;
  mesh.userData.data = data;
  mesh.userData.lastReseed = performance.now();
  mesh.userData.sheenUntil = 0;
  const group = getGroupForSystem(data.cat);
  const name = getEntryName(data.cat, data.entry);
  const color = group?.color || getColorForEntry(name, data.cat);
  const symbolSeed = mesh.userData.symbolIndex + Math.floor(performance.now() / 700);
  const glyph = getGlyph(name, data.cat);
  mesh.material.map = getSymbolTexture(symbolSeed, color, glyph);
  if (mesh.userData.sheenMat) {
    mesh.userData.sheenMat.map = getGlyphMaskTexture(symbolSeed, glyph);
    mesh.userData.sheenMat.opacity = 0;
    mesh.userData.sheenMat.needsUpdate = true;
  }
  mesh.userData.hoverColor = color;
  mesh.material.color.set(highlight ? color : 0xffffff);
  mesh.material.emissive = new THREE.Color(highlight ? color : 0x04141d);
  mesh.material.emissiveIntensity = highlight ? 0.34 : (mesh.userData.baseIntensity || 0.028);
  mesh.material.opacity = 1;
  mesh.material.needsUpdate = true;
}

function buildRubik() {
  assignFaceEntries();
  rubikGroup = new THREE.Group();
  worldGroup.add(rubikGroup);
  let faceCounter = 0;
  let cubeIndex = 0;

  for (let x = -1; x <= 1; x++) {
    for (let y = -1; y <= 1; y++) {
      for (let z = -1; z <= 1; z++) {
        const miniG = new THREE.Group();
        miniG.position.set(x * RUBIK_GAP, y * RUBIK_GAP, z * RUBIK_GAP);
        const coreMat = new THREE.MeshPhysicalMaterial({color:0x03080b, emissive:0x021822, emissiveIntensity:0.42, roughness:0.24, metalness:0.62, clearcoat:1, clearcoatRoughness:0.12});
        miniG.add(new THREE.Mesh(getRoundedBoxGeometry(0.86,0.86,0.86,0.11,0.035), coreMat));
        const shellMat = new THREE.MeshPhysicalMaterial({color:0x79e8ff, transparent:true, opacity:0.095, depthWrite:false, metalness:0.84, roughness:0.08, clearcoat:1, clearcoatRoughness:0.05, side:THREE.DoubleSide});
        miniG.add(new THREE.Mesh(getRoundedBoxGeometry(1.0,1.0,1.0,0.12,0.028), shellMat));
        const wireMat = new THREE.LineBasicMaterial({color:0xbdefff, transparent:true, opacity:0.1});
        miniG.add(new THREE.LineSegments(new THREE.EdgesGeometry(getRoundedBoxGeometry(0.98,0.98,0.98,0.11,0.025)), wireMat));
        const faceMaterials = [];

        FACE_CONFIGS.forEach((fc, fi) => {
          const show = (fc.side === 'front' && z === 1) || (fc.side === 'back' && z === -1) ||
            (fc.side === 'right' && x === 1) || (fc.side === 'left' && x === -1) ||
            (fc.side === 'top' && y === 1) || (fc.side === 'bottom' && y === -1);
          if (!show) return;
          const fData = faceEntryMap[faceCounter % faceEntryMap.length];
          const group = getGroupForSystem(fData.cat);
          const name = getEntryName(fData.cat, fData.entry);
          const color = group?.color || getColorForEntry(name, fData.cat);
          const tex = getSymbolTexture(faceCounter, color, getGlyph(name, fData.cat));
          const fMat = new THREE.MeshPhysicalMaterial({
            map: tex, color:0xffffff, transparent:true, alphaTest:0.04, opacity:1,
            emissive:new THREE.Color(0x04141d), emissiveIntensity:0.028,
            side:THREE.DoubleSide, roughness:0.26, metalness:0.24, clearcoat:1, clearcoatRoughness:0.11
          });
          faceMaterials.push(fMat);
          const fMesh = new THREE.Mesh(new THREE.PlaneGeometry(0.88, 0.88), fMat);
          fMesh.position.set(...fc.pos.map(v => v * 1.035));
          fMesh.rotation.set(...fc.rot);
          fMesh.userData = {type:'rubik', faceIdx:faceCounter, cubeIndex, faceSide:fc.side, symbolIndex:faceCounter, data:fData, hoverColor:color, baseIntensity:0.028, baseOpacity:1};
          miniG.add(fMesh);
          const sheenMat = new THREE.MeshBasicMaterial({
            map:getGlyphMaskTexture(faceCounter, getGlyph(name, fData.cat)),
            color:0xffffff,
            transparent:true,
            opacity:0,
            blending:THREE.NormalBlending,
            depthWrite:false,
            toneMapped:false,
            side:THREE.DoubleSide
          });
          const sheenMesh = new THREE.Mesh(new THREE.PlaneGeometry(0.88, 0.88), sheenMat);
          sheenMesh.position.set(...fc.pos.map(v => v * 1.052));
          sheenMesh.rotation.set(...fc.rot);
          sheenMesh.renderOrder = 5;
          fMesh.userData.sheenMat = sheenMat;
          miniG.add(sheenMesh);
          allFaces.push(fMesh);
          faceCounter++;
        });
        miniG.userData = {coreMat, shellMat, wireMat, faceMaterials};
        rubikMiniCubes.push(miniG);
        rubikGroup.add(miniG);
        cubeIndex++;
      }
    }
  }
}

function reseedFaces(force = false) {
  if (!camera) return;
  const camDir = new THREE.Vector3();
  camera.getWorldDirection(camDir);
  allFaces.forEach(mesh => {
    if (mesh.userData.type !== 'rubik') return;
    const normal = new THREE.Vector3(0,0,1).applyQuaternion(mesh.getWorldQuaternion(new THREE.Quaternion()));
    const dot = normal.dot(camDir);
    if (force || dot > 0.28) applyFaceData(mesh, getRandomEntry(), mesh === hoveredMesh);
  });
}

const CUBE_GROUPS = [
  {name:'PRIMORDIAL', color:'#ff6688', systems:['ALCHEMY','ELEMENTS','METALS','CRYSTALS','COLORS','PLATONIC_SOLIDS']},
  {name:'CELESTIAL',  color:'#c9a84c', systems:['PLANETS','ZODIAC','MAJOR_ARCANA','MINOR_ARCANA','NUMBERS','NOTES']},
  {name:'SYMBOLIC',   color:'#9d4edd', systems:['KABBALAH','I_CHING','GEOMANCY','MAYAN','LETTERS_HEBREW','LETTERS_LATIN','GEOMETRY']},
  {name:'EMBODIED',   color:'#00f5ff', systems:['ARCHETYPES','DEITIES','PHYSIOLOGY','CHAKRAS','FREQUENCY','PLANTS','VICES','VIRTUES']}
];

function getGroupForSystem(system) {
  return CUBE_GROUPS.find(group => group.systems.includes(system));
}

function buildGroupLegend() {
  const legend = document.getElementById('categoryLegend');
  if (!legend) return;
  legend.innerHTML = `<div class="legend-title">CATEGORIES</div>` + CUBE_GROUPS.map(group =>
    `<div class="legend-item" style="color:${group.color}"><span class="legend-dot"></span><span>${group.name}</span></div>`
  ).join('');
}

function showGroupCategory(groupIdx) {
  pointerDown = false;
  clearHoverState();
  destroyCardCube();
  const group = CUBE_GROUPS[groupIdx];
  if (!group) return;
  closeOracle();
  const overlay = document.getElementById('cardOverlay');
  const rows = group.systems.filter(key => CAT_META[key]).map(key => {
    const meta = CAT_META[key] || {color:group.color, label:key, icon:''};
    const count = CODEX[key]?.length || 0;
    return `<div class="group-system-item" data-open-cat="${escapeHTML(key)}">
      <div class="group-system-icon" style="color:${meta.color}">${meta.icon}</div>
      <div>
        <div class="group-system-name">${escapeHTML(meta.label || key.replace(/_/g,' '))}</div>
        <div class="group-system-meta">${count} entries in ${escapeHTML(group.name)}</div>
      </div>
    </div>`;
  }).join('');
  overlay.innerHTML = `<div class="group-card">
    <div class="catview-header">
      <div>
        <div class="catview-icon" style="color:${group.color}">CATEGORY CUBE</div>
        <div class="catview-title" style="color:${group.color}">${escapeHTML(group.name)}</div>
        <div class="catview-count">${group.systems.length} systems</div>
      </div>
      <button class="card-close-btn" onclick="closeOverlay()">X</button>
    </div>
    <div class="group-system-list">${rows}</div>
  </div>`;
  overlay.classList.add('open');
  setStatus(`${group.name} CATEGORY - ${group.systems.length} SYSTEMS`);
}

function buildOrbitCubes() {
  CUBE_GROUPS.forEach((group, gi) => {
    const cubeG = new THREE.Group();
    const groupColor = new THREE.Color(group.color);
    const coreMat = new THREE.MeshPhysicalMaterial({color:0x020608, metalness:0.5, roughness:0.2, transparent:false, opacity:1, emissive:groupColor, emissiveIntensity:0.16, clearcoat:1, clearcoatRoughness:0.05});
    cubeG.add(new THREE.Mesh(getRoundedBoxGeometry(0.84,0.84,0.84,0.1,0.035), coreMat));
    const shellMat = new THREE.MeshPhysicalMaterial({color:groupColor, transparent:true, opacity:0.08, depthWrite:false, metalness:0.62, roughness:0.05, clearcoat:1, clearcoatRoughness:0.02, side:THREE.DoubleSide});
    cubeG.add(new THREE.Mesh(getRoundedBoxGeometry(1.02,1.02,1.02,0.12,0.028), shellMat));
    const wireMat = new THREE.LineBasicMaterial({color:groupColor, transparent:true, opacity:0.34});
    cubeG.add(new THREE.LineSegments(new THREE.EdgesGeometry(getRoundedBoxGeometry(0.94,0.94,0.94,0.1,0.024)), wireMat));
    const outerWireMat = new THREE.LineBasicMaterial({color:groupColor, transparent:true, opacity:0.12});
    cubeG.add(new THREE.LineSegments(new THREE.EdgesGeometry(getRoundedBoxGeometry(1.07,1.07,1.07,0.12,0.024)), outerWireMat));
    const faceMaterials = [];

    FACE_CONFIGS.forEach((fc, fi) => {
      const tex = getSymbolTexture(54 + gi * 8 + fi, group.color, group.name.slice(0, 3));
      const fMat = new THREE.MeshPhysicalMaterial({map:tex, color:0xffffff, transparent:true, alphaTest:0.04, opacity:1, emissive:new THREE.Color(0x04141d), emissiveIntensity:0.028, side:THREE.DoubleSide, roughness:0.16, metalness:0.22, clearcoat:1, clearcoatRoughness:0.03});
      faceMaterials.push(fMat);
      const fMesh = new THREE.Mesh(new THREE.PlaneGeometry(0.78,0.78), fMat);
      fMesh.position.set(...fc.pos.map(v => v * 0.92));
      fMesh.rotation.set(...fc.rot);
      fMesh.userData = {type:'orbitGroup', groupIdx:gi, faceIdx:fi, hoverColor:group.color, baseIntensity:0.08, baseOpacity:1};
      cubeG.add(fMesh);
      allFaces.push(fMesh);
    });

    const iLight = new THREE.PointLight(groupColor, 0.38, 3.5);
    cubeG.add(iLight);
    const orbitRadii = [3.45, 4.4, 3.45, 4.4];
    const orbitLanes = [-1.32, -0.42, 0.54, 1.44];
    cubeG.userData = {type:'orbitCube', groupIdx:gi, baseAngle:gi * Math.PI / 2, baseRadius:orbitRadii[gi], yBase:orbitLanes[gi], orbitSpeed:0.115 + gi * 0.018, floatSeed:gi * 1.47, coreMat, shellMat, wireMat, outerWireMat, faceMaterials};
    orbitCubes.push(cubeG);
    worldGroup.add(cubeG);
  });
}

// CONTROLS
// ═══════════════════════════════════════════════════════
function setupControls() {
  const el = centerArea;
  el.addEventListener('contextmenu', e => {
    if (!isUiEventTarget(e.target)) e.preventDefault();
  });

  el.addEventListener('pointerdown', e => {
    if (isUiEventTarget(e.target)) {
      pointerDown = false;
      pointerMode = 'rotate';
      clearHoverState();
      return;
    }
    pointerDown = true;
    pointerMode = e.button === 2 ? 'pan' : 'rotate';
    pointerMoved = false;
    pointerStart = {x:e.clientX, y:e.clientY};
    pointerPrev = {x:e.clientX, y:e.clientY};
    el.setPointerCapture?.(e.pointerId);
  });

  el.addEventListener('pointermove', e => {
    if (isUiEventTarget(e.target) && !pointerDown) return;
    updateMouse(e.clientX, e.clientY);
    if (pointerDown) {
      const dx = e.clientX - pointerPrev.x, dy = e.clientY - pointerPrev.y;
      if (Math.hypot(e.clientX - pointerStart.x, e.clientY - pointerStart.y) > 4) pointerMoved = true;
      if (worldGroup && pointerMode === 'pan') {
        worldGroup.position.x += dx * 0.006;
        worldGroup.position.y -= dy * 0.006;
        centerArea.style.cursor = 'move';
      } else if (worldGroup) {
        worldGroup.rotation.y += dx * 0.007;
        worldGroup.rotation.x += dy * 0.007;
        centerArea.style.cursor = 'grabbing';
      }
      pointerPrev = {x:e.clientX, y:e.clientY};
      return;
    }
    updateHoverState(e.clientX, e.clientY);
  });

  el.addEventListener('pointerup', e => {
    if (isUiEventTarget(e.target)) {
      pointerDown = false;
      pointerMode = 'rotate';
      clearHoverState();
      return;
    }
    updateMouse(e.clientX, e.clientY);
    if (!pointerMoved && pointerMode !== 'pan') handleSceneClick(e);
    else centerArea.style.cursor = 'default';
    pointerDown = false;
    pointerMode = 'rotate';
  });

  el.addEventListener('pointerleave', () => {
    pointerDown = false;
    pointerMode = 'rotate';
    clearHoverState();
  });

  el.addEventListener('wheel', e => {
    if (isUiEventTarget(e.target) || e.target.closest('.entry-list,.card-corrs,.search-results,.group-system-list,.stream-card')) return;
    e.preventDefault();
    camera.position.z = Math.max(3.6, Math.min(13, camera.position.z + e.deltaY * 0.004));
  }, {passive:false});
}

function updateMouse(clientX, clientY) {
  const rect = centerArea.getBoundingClientRect();
  mouse.x = ((clientX - rect.left) / rect.width) * 2 - 1;
  mouse.y = -((clientY - rect.top) / rect.height) * 2 + 1;
}

function raycastFaces() {
  raycaster.setFromCamera(mouse, camera);
  return raycaster.intersectObjects(allFaces, false);
}

function clearHoverState() {
  hoveredMesh = null;
  centerArea.style.cursor = 'default';
  document.getElementById('cubeTip').classList.remove('show');
  allFaces.forEach(f => {
    if (f.userData.sheenUntil && f.userData.sheenUntil > performance.now()) return;
    resetFaceMaterial(f);
  });
}

function updateHoverState(clientX, clientY) {
  const hits = raycastFaces();
  if (!hits.length) { clearHoverState(); return; }
  const mesh = hits[0].object;
  if (hoveredMesh && hoveredMesh !== mesh && hoveredMesh.material) {
    resetFaceMaterial(hoveredMesh);
  }
  hoveredMesh = mesh;
  centerArea.style.cursor = 'pointer';
  if (mesh.material) {
    const d = mesh.userData;
    let color = '#00f5ff';
    if (d.type === 'rubik' && d.data) color = getGroupForSystem(d.data.cat)?.color || CAT_META[d.data.cat]?.color || color;
    if (d.type === 'orbitGroup') color = CUBE_GROUPS[d.groupIdx]?.color || color;
    mesh.material.color?.set?.(color);
    mesh.material.emissive = new THREE.Color(color);
    mesh.material.emissiveIntensity = 0.34;
    mesh.material.opacity = 1;
  }
  showCubeTooltip(mesh.userData, clientX, clientY);
}

function showCubeTooltip(data, clientX, clientY) {
  const tip = document.getElementById('cubeTip');
  let html = '';
  let color = '#00f5ff';
  if (data.type === 'orbitGroup') {
    const group = CUBE_GROUPS[data.groupIdx];
    color = group.color;
    html = `<div class="tip-kicker">CATEGORY CUBE</div><div class="tip-title" style="color:${color}">${escapeHTML(group.name)}</div><div class="tip-meta">${group.systems.length} systems - click to open category</div>`;
  } else if (data.type === 'rubik' && data.data) {
    const ref = data.data;
    const meta = CAT_META[ref.cat] || {label:ref.cat, icon:''};
    const group = getGroupForSystem(ref.cat);
    const name = getEntryName(ref.cat, ref.entry);
    const element = splitValues(ref.entry.ELEMENTS)[0] || 'unmapped element';
    color = group?.color || meta.color || color;
    html = `<div class="tip-kicker">${escapeHTML(group?.name || 'SYSTEM')} / ${escapeHTML(meta.label || ref.cat)}</div><div class="tip-title" style="color:${color}">${meta.icon} ${escapeHTML(name)}</div><div class="tip-meta">Element: ${escapeHTML(element)}<br>click to open card</div>`;
  }
  if (!html) return;
  const rect = centerArea.getBoundingClientRect();
  tip.innerHTML = html;
  tip.style.left = Math.min(rect.width - 280, Math.max(8, clientX - rect.left + 12)) + 'px';
  tip.style.top = Math.max(8, clientY - rect.top - 26) + 'px';
  tip.classList.add('show');
}

function handleSceneClick(e) {
  if (isUiEventTarget(e.target) || document.getElementById('cardOverlay')?.classList.contains('open') || document.getElementById('streamOverlay')?.classList.contains('on')) return;
  const hits = raycastFaces();
  if (!hits.length) return;
  const d = hits[0].object.userData;
  if (d.type === 'orbitGroup') {
    showGroupCategory(d.groupIdx);
  } else if (d.type === 'rubik' && d.data) {
    selectEntry(d.data.cat, d.data.idx);
  }
}

// ANIMATE
// ═══════════════════════════════════════════════════════
let reseedTimer = 0;
function animate() {
  requestAnimationFrame(animate);
  const dt = clock.getDelta();
  const t = clock.elapsedTime;
  const now = performance.now();
  ensureMainSceneIntegrity();

  if (autoRot && worldGroup) {
    worldGroup.rotation.y += 0.0022;
    if (rubikGroup && !isRubikTurning) {
      rubikGroup.rotation.y += 0.0008;
      queueRandomRubikTurn(now);
    }
  }

  rubikMiniCubes.forEach((cube, i) => {
    const u = cube.userData;
    if (!u) return;
    if (u.shellMat) u.shellMat.opacity = 0.08 + (Math.sin(t * 1.4 + i * 0.45) + 1) * 0.026;
    if (u.wireMat) u.wireMat.opacity = 0.07 + (Math.sin(t * 1.1 + i * 0.32) + 1) * 0.035;
    if (u.faceMaterials) u.faceMaterials.forEach((m, fi) => {
      if (!hoveredMesh || hoveredMesh.material !== m) m.emissiveIntensity = 0.03 + (Math.sin(t * 1.15 + i * 0.25 + fi) + 1) * 0.02;
    });
  });

  orbitCubes.forEach((cube, i) => {
    const u = cube.userData;
    const angle = u.baseAngle + t * u.orbitSpeed;
    const radius = u.baseRadius + Math.sin(t * 0.37 + u.floatSeed) * 0.08;
    const yOff = u.yBase + Math.sin(t * 0.51 + i * 1.7) * 0.18;
    cube.position.set(Math.cos(angle) * radius, yOff, Math.sin(angle) * radius);
    cube.rotation.y += 0.0075;
    cube.rotation.x += 0.0038;
    cube.rotation.z = Math.sin(t * 0.72 + i) * 0.12;
    u.coreMat.opacity = 1;
    u.coreMat.emissiveIntensity = 0.12 + (Math.sin(t * 1.35 + i * 1.2) + 1) * 0.055;
    u.shellMat.opacity = 0.045 + (Math.sin(t * 1.7 + i * 0.8) + 1) * 0.025;
    u.outerWireMat.opacity = 0.08 + (Math.sin(t * 2 + i) + 1) * 0.05;
  });

  reseedTimer += dt;
  updateRandomFaceSheen(now);
  if (reseedTimer > 1.8) { reseedTimer = 0; reseedFaces(false); }
  renderer.render(scene, camera);
}

function resetFaceMaterial(mesh) {
  if (!mesh?.material) return;
  mesh.material.color?.set?.(0xffffff);
  mesh.material.emissive?.set?.(0x06232f);
  mesh.material.emissiveIntensity = mesh.userData.baseIntensity || 0.08;
  mesh.material.opacity = mesh.userData.baseOpacity || 1;
  if (mesh.userData.sheenMat) mesh.userData.sheenMat.opacity = 0;
}

function updateRandomFaceSheen(now) {
  if (now > nextSheenAt) {
    const faces = allFaces.filter(face => face.userData.type === 'rubik' && face !== hoveredMesh && now - (face.userData.lastReseed || 0) > 1200);
    shuffleInPlace(faces);
    const count = 1 + Math.floor(Math.random() * 3);
    faces.slice(0, count).forEach(face => {
      face.userData.sheenUntil = now + 980 + Math.random() * 1200;
      face.userData.sheenSeed = Math.random() * 360;
    });
    nextSheenAt = now + 360 + Math.random() * 320;
  }
  allFaces.forEach(face => {
    if (face.userData.type !== 'rubik' || face === hoveredMesh) return;
    const until = face.userData.sheenUntil || 0;
    if (until > now) {
      const p = 1 - ((until - now) / 2000);
      const pulse = Math.sin(Math.max(0, Math.min(1, p)) * Math.PI);
      const hue = ((face.userData.sheenSeed || 0) + now * 0.48) % 360;
      if (face.userData.sheenMat) {
        face.userData.sheenMat.color.setHSL(hue / 360, 1, 0.52);
        face.userData.sheenMat.opacity = Math.min(0.96, 0.58 + pulse * 0.38);
      }
    } else if (face.userData.sheenUntil) {
      face.userData.sheenUntil = 0;
      resetFaceMaterial(face);
    }
  });
}

function ensureMainSceneIntegrity() {
  if (!worldGroup || !rubikGroup || !camera || !renderer) return;
  worldGroup.visible = true;
  rubikGroup.visible = true;
  if (!Number.isFinite(worldGroup.position.x) || !Number.isFinite(worldGroup.position.y) || Math.abs(worldGroup.position.x) > 20 || Math.abs(worldGroup.position.y) > 20) {
    worldGroup.position.set(0, 0, 0);
  }
  if (rubikGroup.parent !== worldGroup && !isRubikTurning) worldGroup.add(rubikGroup);
  if (!isRubikTurning) {
    rubikMiniCubes.forEach(cube => {
      if (!cube.parent) rubikGroup.add(cube);
      cube.visible = true;
      cube.traverse?.(obj => { obj.visible = true; });
    });
  }
  rubikGroup.scale.set(1, 1, 1);
  if (!Number.isFinite(camera.position.z) || camera.position.z < 3.2 || camera.position.z > 14) camera.position.z = 8.6;
  camera.lookAt(0, 0, 0);
}

function queueRandomRubikTurn(now) {
  if (isRubikTurning || now < nextRubikTurnAt) return;
  const axes = ['x', 'y', 'z'];
  const axis = axes[Math.floor(Math.random() * axes.length)];
  const slice = Math.floor(Math.random() * 3) - 1;
  const direction = Math.random() > 0.5 ? 1 : -1;
  rotateRubikSlice(axis, slice, direction, 950);
  nextRubikTurnAt = now + 3400 + Math.random() * 2200;
}

function rotateRubikSlice(axis, slice, direction, duration = 950) {
  if (isRubikTurning || !rubikGroup) return;
  const active = rubikMiniCubes.filter(cube => Math.abs(cube.position[axis] - slice * RUBIK_GAP) < 0.12);
  if (!active.length) return;
  isRubikTurning = true;
  const pivot = new THREE.Group();
  rubikGroup.add(pivot);
  active.forEach(cube => pivot.attach(cube));
  const start = performance.now();
  const to = (Math.PI / 2) * direction;
  function step(now) {
    const p = Math.min(1, (now - start) / duration);
    const eased = p < 0.5 ? 4 * p * p * p : 1 - Math.pow(-2 * p + 2, 3) / 2;
    pivot.rotation[axis] = to * eased;
    if (p < 1) { requestAnimationFrame(step); return; }
    pivot.updateMatrixWorld(true);
    active.forEach(cube => {
      rubikGroup.attach(cube);
      cube.position.x = Math.round(cube.position.x / RUBIK_GAP) * RUBIK_GAP;
      cube.position.y = Math.round(cube.position.y / RUBIK_GAP) * RUBIK_GAP;
      cube.position.z = Math.round(cube.position.z / RUBIK_GAP) * RUBIK_GAP;
      cube.rotation.x = Math.round(cube.rotation.x / (Math.PI / 2)) * (Math.PI / 2);
      cube.rotation.y = Math.round(cube.rotation.y / (Math.PI / 2)) * (Math.PI / 2);
      cube.rotation.z = Math.round(cube.rotation.z / (Math.PI / 2)) * (Math.PI / 2);
    });
    rubikGroup.remove(pivot);
    isRubikTurning = false;
    reseedFaces(false);
  }
  requestAnimationFrame(step);
}

// MINI CARD CUBE (CSS 3D)
// ═══════════════════════════════════════════════════════
let cardCubeRuntime = null;
let glyphMaskTextures = {};

function destroyCardCube() {
  if (!cardCubeRuntime) return;
  const runtime = cardCubeRuntime;
  cardCubeRuntime = null;
  cancelAnimationFrame(runtime.raf);
  runtime.renderer?.dispose?.();
}

function renderCardCubeFallback(cat, entry, glyph = '', color = '#00f5ff') {
  destroyCardCube();
  const container = document.querySelector('.card-cube-container');
  const name = getEntryName(cat, entry);
  if (!container) return;
  container.innerHTML = `<div class="card-cube-fallback" style="--c:${color}">
    <div class="card-cube-fallback-glyph">${glyph || getGlyph(name, cat)}</div>
    <div class="card-cube-fallback-title">${escapeHTML(name)}</div>
    <div class="card-cube-fallback-sub">LITE TELEMETRY NODE</div>
  </div>`;
}

function initCardCube(cat, entry) {
  const canvas = document.getElementById('cardCubeCanvas');
  if (!canvas || !THREE || DEVICE_TIER === 'fallback') {
    const name = getEntryName(cat, entry);
    renderCardCubeFallback(cat, entry, getGlyph(name, cat), getColorForEntry(name, cat));
    return;
  }
  destroyCardCube();

  const tip = document.getElementById('cardCubeTip');
  const renderer2 = new THREE.WebGLRenderer({canvas, antialias:true, alpha:true});
  renderer2.setClearColor(0x000000, 0);
  renderer2.domElement.style.background = 'transparent';
  const scene2 = new THREE.Scene();
  const camera2 = new THREE.PerspectiveCamera(44, 1, 0.1, 50);
  camera2.position.set(0, 0, 4.15);
  scene2.add(new THREE.AmbientLight(0xffffff, 0.5));
  const lightA = new THREE.PointLight(0x00f5ff, 0.72, 10); lightA.position.set(2, 2, 3); scene2.add(lightA);
  const lightB = new THREE.PointLight(0xc9a84c, 0.42, 10); lightB.position.set(-2, -1.4, 2.6); scene2.add(lightB);

  const cube = new THREE.Group();
  scene2.add(cube);
  let cardFaceLockUntil = 0;
  const core = new THREE.Mesh(getRoundedBoxGeometry(1.32,1.32,1.32,0.14,0.04), new THREE.MeshPhysicalMaterial({color:0x03080b, emissive:0x021624, emissiveIntensity:0.38, metalness:0.62, roughness:0.25, clearcoat:1, clearcoatRoughness:0.12}));
  cube.add(core);
  const shell = new THREE.Mesh(getRoundedBoxGeometry(1.5,1.5,1.5,0.16,0.035), new THREE.MeshPhysicalMaterial({color:0x5adfff, transparent:true, opacity:0.055, depthWrite:false, metalness:0.78, roughness:0.12, clearcoat:1, side:THREE.DoubleSide}));
  cube.add(shell);
  cube.add(new THREE.LineSegments(new THREE.EdgesGeometry(getRoundedBoxGeometry(1.48,1.48,1.48,0.15,0.028)), new THREE.LineBasicMaterial({color:0x9defff, transparent:true, opacity:0.12})));

  const orderedSystems = [cat, ...SYSTEM_ORDER.filter(key => key !== cat)];
  let systemCursor = 0;
  const faceMeshes = [];
  const raycaster2 = new THREE.Raycaster();
  const mouse2 = new THREE.Vector2();
  let hovered = null;
  let pressedFace = null;
  let pressPoint = {x:0, y:0};
  let suppressNextClick = false;
  let nextCardSheenAt = 0;

  function nextSystem() {
    const key = orderedSystems[systemCursor % orderedSystems.length];
    systemCursor++;
    return key;
  }

  function setCardFace(mesh, key) {
    const meta = CAT_META[key] || {color:'#00f5ff', label:key, icon:''};
    const rawValue = entry[key] || '';
    const first = splitValues(rawValue)[0] || (meta.label || key);
    mesh.userData.system = key;
    mesh.userData.value = rawValue;
    const target = resolveEntryRef(key, rawValue);
    mesh.userData.targetCat = target?.cat || key;
    mesh.userData.targetIdx = Number.isInteger(target?.idx) ? target.idx : null;
    mesh.userData.hoverColor = meta.color;
    mesh.userData.lastSeed = performance.now();
    mesh.material.map = getSymbolTexture(120 + systemCursor * 7 + mesh.userData.faceIdx, meta.color, getGlyph(first, key));
    if (mesh.userData.sheenMat) {
      mesh.userData.sheenMat.map = getGlyphMaskTexture(120 + systemCursor * 7 + mesh.userData.faceIdx, getGlyph(first, key));
      mesh.userData.sheenMat.needsUpdate = true;
    }
    mesh.material.color.set(mesh === hovered ? meta.color : 0xffffff);
    mesh.material.emissive = new THREE.Color(mesh === hovered ? meta.color : 0x06232f);
    mesh.material.emissiveIntensity = mesh === hovered ? 0.34 : 0.08;
    mesh.material.opacity = 1;
    mesh.material.needsUpdate = true;
  }

  FACE_CONFIGS.forEach((fc, fi) => {
    const mat = new THREE.MeshPhysicalMaterial({map:getSymbolTexture(120 + fi, '#00f5ff', '*'), color:0xffffff, transparent:true, alphaTest:0.04, opacity:1, emissive:0x06232f, emissiveIntensity:0.08, side:THREE.DoubleSide, roughness:0.22, metalness:0.24, clearcoat:1, clearcoatRoughness:0.1});
    const mesh = new THREE.Mesh(new THREE.PlaneGeometry(1.2,1.2), mat);
    mesh.position.set(...fc.pos.map(v => v * 1.42));
    mesh.rotation.set(...fc.rot);
    mesh.userData = {type:'cardFace', faceIdx:fi, baseIntensity:0.08, baseOpacity:1};
    const sheenMat = new THREE.MeshBasicMaterial({map:getGlyphMaskTexture(120 + fi, '*'), color:0xffffff, transparent:true, opacity:0, blending:THREE.NormalBlending, depthWrite:false, toneMapped:false, side:THREE.DoubleSide});
    const sheenMesh = new THREE.Mesh(new THREE.PlaneGeometry(1.2,1.2), sheenMat);
    sheenMesh.position.set(...fc.pos.map(v => v * 1.445));
    sheenMesh.rotation.set(...fc.rot);
    sheenMesh.renderOrder = 5;
    mesh.userData.sheenMat = sheenMat;
    setCardFace(mesh, nextSystem());
    cube.add(mesh);
    cube.add(sheenMesh);
    faceMeshes.push(mesh);
  });

  function sizeRenderer() {
    const rect = canvas.getBoundingClientRect();
    const w = Math.max(1, Math.floor(rect.width));
    const h = Math.max(1, Math.floor(rect.height));
    renderer2.setSize(w, h, false);
    renderer2.setPixelRatio(Math.min(window.devicePixelRatio || 1, RENDER_PROFILE.dpr));
    camera2.aspect = w / h;
    camera2.updateProjectionMatrix();
  }

  function clearCardHover() {
    hovered = null;
    if (tip) tip.classList.remove('show');
    faceMeshes.forEach(mesh => {
      mesh.material.color.set(0xffffff);
      mesh.material.emissive.set(0x06232f);
      mesh.material.emissiveIntensity = mesh.userData.baseIntensity;
      mesh.material.opacity = mesh.userData.baseOpacity;
      if (mesh.userData.sheenMat && !(mesh.userData.sheenUntil > performance.now())) mesh.userData.sheenMat.opacity = 0;
    });
  }

  function pickCardFace(e) {
    const rect = canvas.getBoundingClientRect();
    mouse2.x = ((e.clientX - rect.left) / rect.width) * 2 - 1;
    mouse2.y = -((e.clientY - rect.top) / rect.height) * 2 + 1;
    raycaster2.setFromCamera(mouse2, camera2);
    const hits = raycaster2.intersectObjects(faceMeshes, false);
    return hits[0]?.object || null;
  }

  function openCardFace(mesh) {
    if (!mesh?.userData) return;
    const key = mesh.userData.system;
    const targetCat = mesh.userData.targetCat;
    const targetIdx = mesh.userData.targetIdx;
    requestAnimationFrame(() => {
      if (Number.isInteger(targetIdx) && CODEX[targetCat]?.[targetIdx]) selectEntry(targetCat, targetIdx);
      else if (CODEX[key]) selectCategory(key);
    });
  }

  canvas.addEventListener('pointerdown', e => {
    e.preventDefault();
    e.stopPropagation();
    pressedFace = pickCardFace(e);
    pressPoint = {x:e.clientX, y:e.clientY};
    cardFaceLockUntil = performance.now() + 2400;
  });
  canvas.addEventListener('pointerup', e => {
    e.preventDefault();
    e.stopPropagation();
    const moved = Math.hypot(e.clientX - pressPoint.x, e.clientY - pressPoint.y);
    const hit = pickCardFace(e) || pressedFace;
    if (hit && moved < 7) {
      suppressNextClick = true;
      openCardFace(hit);
    }
    pressedFace = null;
  });

  canvas.addEventListener('pointermove', e => {
    e.stopPropagation();
    cardFaceLockUntil = performance.now() + 1400;
    const hit = pickCardFace(e);
    if (!hit) { canvas.style.cursor = 'default'; clearCardHover(); return; }
    hovered = hit;
    canvas.style.cursor = 'pointer';
    faceMeshes.forEach(mesh => {
      const hoverColor = mesh.userData.hoverColor || '#00f5ff';
      mesh.material.color.set(mesh === hovered ? hoverColor : 0xffffff);
      mesh.material.emissive.set(mesh === hovered ? hoverColor : 0x06232f);
      mesh.material.emissiveIntensity = mesh === hovered ? 0.34 : mesh.userData.baseIntensity;
      mesh.material.opacity = mesh === hovered ? 1 : mesh.userData.baseOpacity;
      if (mesh.userData.sheenMat && mesh === hovered) {
        mesh.userData.sheenMat.color.set(hoverColor);
        mesh.userData.sheenMat.opacity = 0.72;
      }
    });
    if (tip) {
      const key = hovered.userData.system;
      const meta = CAT_META[key] || {color:'#00f5ff', label:key, icon:''};
      const first = splitValues(hovered.userData.value)[0] || hovered.userData.value || 'No correspondence';
      tip.innerHTML = `<div class="tip-kicker">${escapeHTML(meta.label || key)}</div><div class="tip-title" style="color:${meta.color}">${meta.icon} ${escapeHTML(truncate(first, 44))}</div><div class="tip-meta">click to open mapped entry</div>`;
      tip.classList.add('show');
    }
  });

  canvas.addEventListener('pointerleave', clearCardHover);
  canvas.addEventListener('click', e => {
    e.preventDefault();
    e.stopPropagation();
    if (suppressNextClick) { suppressNextClick = false; return; }
    const hit = pickCardFace(e) || hovered;
    openCardFace(hit);
  });

  function reseedHiddenCardFaces() {
    if (performance.now() < cardFaceLockUntil) return;
    const camDir = new THREE.Vector3();
    camera2.getWorldDirection(camDir);
    const now = performance.now();
    faceMeshes.forEach(mesh => {
      const normal = new THREE.Vector3(0,0,1).applyQuaternion(mesh.getWorldQuaternion(new THREE.Quaternion()));
      if (normal.dot(camDir) > 0.2 && now - mesh.userData.lastSeed > 900) setCardFace(mesh, nextSystem());
    });
  }

  function updateCardFaceSheen(now) {
    if (now > nextCardSheenAt) {
      const pool = faceMeshes.filter(mesh => mesh !== hovered && now - (mesh.userData.lastSeed || 0) > 900);
      shuffleInPlace(pool);
      pool.slice(0, 1 + Math.floor(Math.random() * 2)).forEach(mesh => {
        mesh.userData.sheenUntil = now + 920 + Math.random() * 900;
        mesh.userData.sheenSeed = Math.random() * 360;
      });
      nextCardSheenAt = now + 1200 + Math.random() * 900;
    }
    faceMeshes.forEach(mesh => {
      const mat = mesh.userData.sheenMat;
      if (!mat || mesh === hovered) return;
      const until = mesh.userData.sheenUntil || 0;
      if (until > now) {
        const p = 1 - ((until - now) / 1700);
        const pulse = Math.sin(Math.max(0, Math.min(1, p)) * Math.PI);
        const hue = ((mesh.userData.sheenSeed || 0) + now * 0.5) % 360;
        mat.color.setHSL(hue / 360, 1, 0.52);
        mat.opacity = Math.min(0.96, 0.56 + pulse * 0.4);
      } else {
        mat.opacity = 0;
      }
    });
  }

  function frame() {
    if (!cardCubeRuntime || cardCubeRuntime.renderer !== renderer2) return;
    cardCubeRuntime.raf = requestAnimationFrame(frame);
    sizeRenderer();
    const now = performance.now();
    const t = now * 0.001;
    cube.rotation.y += 0.0105;
    cube.rotation.x += 0.0068;
    cube.rotation.z += 0.0028;
    shell.material.opacity = 0.045 + (Math.sin(t * 1.8) + 1) * 0.018;
    reseedHiddenCardFaces();
    updateCardFaceSheen(now);
    renderer2.render(scene2, camera2);
  }

  cardCubeRuntime = {renderer:renderer2, scene:scene2, camera:camera2, raf:0};
  sizeRenderer();
  frame();
}

// UTILITIES
// ═══════════════════════════════════════════════════════
function escapeHTML(value) {
  return String(value ?? '').replace(/[&<>"']/g, ch => ({'&':'&amp;', '<':'&lt;', '>':'&gt;', '"':'&quot;', "'":'&#39;'}[ch]));
}

function jsArg(value) {
  return JSON.stringify(String(value ?? ''));
}

function truncate(value, len = 44) {
  const s = String(value ?? '');
  return s.length > len ? s.slice(0, Math.max(0, len - 3)) + '...' : s;
}

function splitValues(value) {
  return String(value ?? '').split(';').map(s => s.trim()).filter(Boolean);
}

function normalizeName(value) {
  return String(value ?? '')
    .normalize('NFKD')
    .replace(/[\u0300-\u036f]/g, '')
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, ' ')
    .trim();
}

function setStatus(t) {
  const el = document.getElementById('statusText');
  if (el) el.textContent = t;
}

function setSoundButton(on) {
  const btn = document.getElementById('soundBtn');
  if (!btn) return;
  btn.classList.toggle('active', !!on);
  btn.textContent = on ? 'SOUND ON' : 'SOUND OFF';
}

function initAmbience() {
  const audio = document.getElementById('codexAmbience');
  if (!audio) return;
  audio.loop = true;
  audio.volume = 0.34;
  if (DEVICE_TIER === 'fallback') {
    audio.preload = 'none';
    setSoundButton(false);
    setStatus('SOUND READY - TAP TO ENABLE');
    return;
  }
  setSoundButton(true);
  const unlock = () => audio.play().then(() => setSoundButton(true)).catch(() => setSoundButton(false));
  audio.play().then(() => setSoundButton(true)).catch(() => {
    setSoundButton(true);
    document.addEventListener('pointerdown', unlock, {once:true});
    document.addEventListener('keydown', unlock, {once:true});
  });
}

function toggleAmbience() {
  const audio = document.getElementById('codexAmbience');
  if (!audio) return;
  if (audio.paused) {
    audio.volume = 0.34;
    audio.play().then(() => setSoundButton(true)).catch(() => setSoundButton(false));
  } else {
    audio.pause();
    setSoundButton(false);
  }
}

function toggleFullscreen() {
  if (!document.fullscreenElement) {
    document.documentElement.requestFullscreen?.();
  } else {
    document.exitFullscreen?.();
  }
}

