async function shareCodex() {
  const payload = {
    title: 'CORRESPONDENCE CODEX',
    text: 'CORRESPONDENCE CODEX - Xeno-Hexahedronal Nexium Matrix',
    url: location.href
  };
  try {
    if (navigator.share) {
      await navigator.share(payload);
      setStatus('SHARE SIGNAL SENT');
      return;
    }
    await navigator.clipboard?.writeText(payload.url);
    setStatus('CODEX LINK COPIED');
  } catch (err) {
    const mail = `mailto:?subject=${encodeURIComponent(payload.title)}&body=${encodeURIComponent(payload.text + '\n' + payload.url)}`;
    location.href = mail;
  }
}
function hexToRgb(hex) {
  hex = hex.replace('#','');
  if (hex.length===3) hex = hex[0]+hex[0]+hex[1]+hex[1]+hex[2]+hex[2];
  return `${parseInt(hex.substring(0,2),16)},${parseInt(hex.substring(2,4),16)},${parseInt(hex.substring(4,6),16)}`;
}

